import{_ as t,o,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Journeys Dynamic Optimization","description":"","frontmatter":{"title":"Journeys Dynamic Optimization","slug":"journeys-dynamic-optimization"},"headers":[],"relativePath":"marketer-hub/journeys-dynamic-optimization.md","filePath":"marketer-hub/journeys-dynamic-optimization.md"}'),a={name:"marketer-hub/journeys-dynamic-optimization.md"};function r(s,e,l,c,p,u){return o(),n("div",null,[...e[0]||(e[0]=[i('<p>Use Journeys Dynamic Optimization to automate creative testing and visitor allocation percentage adjustment.</p><h2 id="set-up-journeys-dynamic-optimization" tabindex="-1">Set up Journeys Dynamic Optimization <a class="header-anchor" href="#set-up-journeys-dynamic-optimization" aria-label="Permalink to &quot;Set up Journeys Dynamic Optimization&quot;">​</a></h2><h3 id="before-you-begin" tabindex="-1">Before You Begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before You Begin&quot;">​</a></h3><p><a href="./create-journey-banner-or-interstitial.html">Create a Journey</a> if you don’t already have one that you want to optimize. Make sure your Journey has at least two creatives before you set up Journeys Dynamic Optimization.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Make all the changes that you want to make to your Journey before setting up Dynamic Optimization. If you change anything after completing these steps, it will end the automated testing and optimization.</p></div><h3 id="step-1-choose-a-campaign-optimization-metric" tabindex="-1">Step 1: Choose a Campaign Optimization Metric <a class="header-anchor" href="#step-1-choose-a-campaign-optimization-metric" aria-label="Permalink to &quot;Step 1: Choose a Campaign Optimization Metric&quot;">​</a></h3><p>Choose a campaign optimization metric to allow targeted performance tracking and optimization.</p><p>You can choose one of the following metrics:</p><ul><li><strong>Acquisition</strong>: The number of unique users who installed your app from the selected Journey.</li><li><strong>Engagement</strong>: The number of unique users who opened your app from the selected Journey.</li></ul><p>Complete the following steps to select a campaign optimization metric for a Journey:</p><ol><li>In the Branch Dashboard, select the <strong>Journeys</strong> tab. The <strong>Journeys</strong> page will open.</li><li>On the <strong>Journeys</strong> page, select the <strong>Manager</strong> tab.</li><li>Select the three-dot icon on the right side of the Journey you want to change.Select <strong>Edit</strong>. The <strong>Select Audience</strong> page will open.</li><li>Under <strong>Select Campaign Objective</strong>, select the checkbox next to <strong>Acquisition</strong> or <strong>Engagement</strong>. <strong>Acquisition</strong> is selected by default.</li><li>Select the <strong>Continue</strong> button. The <strong>Configure Creatives</strong> page will open.</li></ol><h3 id="step-2-enable-dynamic-a-b-testing" tabindex="-1">Step 2: Enable Dynamic A/B Testing <a class="header-anchor" href="#step-2-enable-dynamic-a-b-testing" aria-label="Permalink to &quot;Step 2: Enable Dynamic A/B Testing&quot;">​</a></h3><p>Enable dynamic A/B testing for a Journey’s creatives.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>To use dynamic A/B testing, your selected Journey must have at least two creatives.</p></div><p>Complete the following steps to enable dynamic A/B testing for a Journey:</p><ol><li>On the <strong>Configure Creatives</strong> page, select the toggle next to <strong>Enable Dynamic A/B Testing</strong>.</li><li>Select <strong>Continue</strong>. The <strong>Validate &amp; Test</strong> page will open.</li><li>Select <strong>Start Journey</strong>.</li></ol>',16)])])}const h=t(a,[["render",r]]);export{g as __pageData,h as default};
